  import sailpoint.object.Identity;
  import sailpoint.object.Application;
  import sailpoint.object.Link;
  import sailpoint.object.AttributeMetaData;
  import sailpoint.object.ProvisioningProject;
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.AuditEvent;

  import sailpoint.api.Provisioner;
  import sailpoint.api.IdentityService;
  import sailpoint.api.ObjectUtil;

  import sailpoint.server.Auditor;

  import sailpoint.tools.Util;

  import java.util.List;
  import java.util.Map;
  import java.util.HashMap;
  import java.util.ArrayList;

  import java.nio.file.Path;
  import java.nio.file.Files;
  import java.nio.file.Paths;
  import java.nio.file.LinkOption;
  import java.nio.charset.Charset;

  import java.util.Scanner;

  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  String	DELIMITER 							= "," ;
  String	COMMA 								= "," ;
  String	EMPTY_STRING 						= "" ;
  String 	APP_NAME_DB_PEOPLESOFT 				= "DB-Peoplesoft-HCM-Primary";
  String 	APP_NAME_IIQ 						= "IIQ";

  String inputFilePath 							= "" ;
  String outputFilePath							= "" ;

  List outputMessages = new ArrayList() ;
  List outputRecords = new ArrayList() ;

  BufferedWriter bw = null ;

  private List readInputFile(String inputFilePath){

    List fileRecords = new ArrayList() ;

    try {

      FileInputStream inputFile = new FileInputStream(inputFilePath);
      Scanner scanner = new Scanner(inputFile);

      while (scanner!=null && scanner.hasNextLine()) {

        String lineString = scanner.nextLine();

        if(Util.isNotNullOrEmpty(lineString)){

          fileRecords.add(lineString);

        }
      }


    } catch (Exception exception){

      addMessage("readInputFile() - " + exception.getMessage()) ;

    } 

    addMessage("No. of Records in input file - " + fileRecords.size()) ;

    return fileRecords ; 

  }

  private void writeToOutputFile(String dataString){

    try{

      if(bw!=null){
      } else {
        Path outPath = Paths.get(outputFilePath); //Absolute Path of Output File
        bw = Files.newBufferedWriter(outPath, Charset.forName("UTF-8"));      

      }

      bw.write(dataString);
      bw.newLine();

    } catch (Exception exception){

      addMessage("writeToOutputFile() - " + exception.getMessage()) ;

    } 

  }


  private void processRestore(){

    List inputRecords = readInputFile(inputFilePath) ;

    if(inputRecords!=null && !Util.isEmpty(inputRecords)){

      processRecords(inputRecords) ;

    }

    if (bw!=null){

      bw.close() ;

    }
  }

  private void processRecords(List inputRecords){

    try {

      String inIdentityCubeName = "" ;
      String auditString1 = "" ;
      String auditString2 = "" ;

      boolean psAccountDeleted = false ;
      boolean identityUpdated = false ;

      int lineCount = 0;


      IdentityService idService = new IdentityService(context) ;

      Application dbPeopleSoftApplObj = context.getObjectByName(Application.class, APP_NAME_DB_PEOPLESOFT);


      for(String inputRecord: inputRecords){

        try {

          lineCount++;

          if ((lineCount % 20) == 0) { context.decache(); }


          String[] inRecordValArray = inputRecord.split(DELIMITER) ;

          // Record layout - username,firstname,lastname,ssn,dob,manager,isContractorManager,contractorManager,ctrexpdt,title,department,departmentNumber

          inIdentityCubeName 		= inRecordValArray[0] ;
          inFirstName 				= inRecordValArray[1] ;
          inLastName 				= inRecordValArray[2] ;
          inSSN 					= inRecordValArray[3] ;
          inDOB 					= inRecordValArray[4] ;
          inManager 				= inRecordValArray[5] ;
          inIsContractorManager 	= inRecordValArray[6] ;
          inContractorManager 		= inRecordValArray[7] ;
          inCtrexpdt 				= inRecordValArray[8] ;
          inTitle 					= inRecordValArray[9] ;
          inDepartment 				= inRecordValArray[10] ;
          inDepartmentNumber 		= inRecordValArray[11] ;

          addMessage("processRecords() - Processing - "+ inIdentityCubeName) ;

          Identity identityObj = context.getObjectByName(Identity.class, inIdentityCubeName);

          Identity managerObj = context.getObjectByName(Identity.class, inManager);

          if(identityObj!=null){

            auditString2 = prepareAuditString2(identityObj, managerObj) ;

            auditString1 = prepareAuditString1(inputRecord) ;

            ObjectUtil.unlockIdentity(context, identityObj);

            psAccountDeleted = deletePSAccount(idService, identityObj, dbPeopleSoftApplObj) ;

            if(psAccountDeleted){

              identityObj.setAttribute("firstname",inFirstName);
              identityObj.setAttribute("lastname",inLastName);
              identityObj.setAttribute("ssn",inSSN);
              identityObj.setAttribute("dob",inDOB);
              identityObj.setAttribute("isContractorManager",inIsContractorManager);
              identityObj.setAttribute("contractorManager",inContractorManager);
              identityObj.setAttribute("ctrexpDt",inCtrexpdt);
              identityObj.setAttribute("title",inTitle);
              identityObj.setAttribute("department",inDepartment);
              identityObj.setAttribute("departmentNumber",inDepartmentNumber);

              identityObj.setAttribute("type","non-hr contractor");
              identityObj.setAttribute("identityType","NonHRContractorPersona");

              identityObj.removeAttribute("employeeId");
              identityObj.removeAttribute("employeeClass");
              identityObj.removeAttribute("employeeType");

              if(managerObj!=null){

                identityObj.setManager(managerObj); 

              }

              identityObj = correctAttributeMetadata(identityObj) ;

              context.saveObject(identityObj);
              context.commitTransaction();

              identityUpdated = true ;

              if(identityUpdated){

                logAudit(identityObj, auditString1, auditString2) ;

                writeToOutputFile(inIdentityCubeName + DELIMITER + "Success" + DELIMITER + EMPTY_STRING) ;

              } else {

                writeToOutputFile(inIdentityCubeName + DELIMITER + "Failure" + DELIMITER + "Identity not updated") ;

              }

            } else {

              writeToOutputFile(inIdentityCubeName + DELIMITER + "Failure" + DELIMITER + "PS Account not deleted") ;

            }

          } else {

            addMessage("processRecords() - Identity not found for - "+ inIdentityCubeName) ;

            writeToOutputFile(inIdentityCubeName + DELIMITER + "Failure" + DELIMITER + "Identity not found") ;

          }

        } catch (Exception exception){

          addMessage("processRecords() - Exception occured for user - "+ inIdentityCubeName + " - " + exception.getMessage()) ;

          writeToOutputFile(inIdentityCubeName + DELIMITER + "Failure" + DELIMITER + "Exception occured - "+ exception.getMessage()) ;

        }

      }

    } catch (Exception exception){

      addMessage("processRecords() - Exception occured - "+ exception.getMessage()) ;


    }

  }

  private boolean deletePSAccount(IdentityService idService, Identity identityObj, Application dbPeopleSoftApplObj) {

    boolean successful = false ;

    List dbPeopleSoftLinks = null ;

    Link dbPeopleSoftAccountLink = null ;
    
    String identityCubeName = "" ;

    try {

      identityCubeName = identityObj.getName() ;

      addMessage("psAccountDeleted() - PS Account deletion for user  - "+ identityCubeName) ;

      dbPeopleSoftLinks = idService.getLinks(identityObj,dbPeopleSoftApplObj) ;

      if(dbPeopleSoftLinks!=null && !Util.isEmpty(dbPeopleSoftLinks) && (dbPeopleSoftLinks.size()==1)){ 

        dbPeopleSoftAccountLink =  dbPeopleSoftLinks.get(0) ;

        String nativeIdentity = dbPeopleSoftAccountLink.getNativeIdentity();

        ProvisioningPlan plan = new ProvisioningPlan();

        AccountRequest acctReq = new AccountRequest();

        acctReq.setApplication(APP_NAME_DB_PEOPLESOFT);
        acctReq.setNativeIdentity(nativeIdentity);
        acctReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Delete);

        plan.add(acctReq);
        plan.setIdentity(identityObj);

        if(plan !=null){

          Provisioner delProv = new Provisioner(context);

          delProv.setNoLocking(true);
          delProv.setLocalUpdate(true);   

          ProvisioningProject project = delProv.compile(plan);

          delProv.execute(plan);
          
          addMessage("processRecords() - PS Account deleted for - "+ identityCubeName + " - with nativeIdentity - " + nativeIdentity) ;

          successful = true ;

        }

      } else {

        addMessage("processRecords() - No PS Account found for - "+ identityCubeName) ;

        writeToOutputFile(identityCubeName + DELIMITER + "Failure" + DELIMITER + "No PS Account found") ;

      }  


    } catch (Exception exception){

      addMessage("psAccountDeleted() - Exception occured during PS Account deletion for  - "+ exception.getMessage()) ;

    }

    addMessage("psAccountDeleted() - PS Account deletion successful for user - "+ identityCubeName + " - " + successful) ;

    return successful ;

  }


  private void addMessage(String message) {

    outputMessages.add(message) ;
  }


  private boolean updateIdentity(List attributeRequests, Identity identityObj){

    boolean successful = false ;

    try {

      ProvisioningPlan plan = new ProvisioningPlan();

      AccountRequest accountReq = new AccountRequest();
      accountReq.setOperation(AccountRequest.Operation.Modify);
      accountReq.setNativeIdentity(identityObj.getName());
      accountReq.setApplication(APP_NAME_IIQ);

      accountReq.addAll(attributeRequests);

      List accountReqList = new ArrayList();

      accountReqList.add(accountReq);
      plan.setAccountRequests(accountReqList);
      plan.setIdentity(identityObj);


      Provisioner provisioner = new Provisioner(context);
      provisioner.setLocalUpdate(true);
      provisioner.setNoLocking(true);
      provisioner.execute(plan);

      successful = true ;


    } catch (Exception exception){

      addMessage("updateIdentity - Exception occured Updating identity  - "+ identityObj.getName() + " - " +exception.getMessage()) ;

    }

    addMessage("psAccountDeleted() - Update Identity  - "+ identityCubeName + " - " + successful) ;

    return successful ;

  }

  private List prepareAttributeMetaData(Identity identityObj, String attrName, String source, List attributeMetadataTobeSet) {

    AttributeMetaData attrMetaData = null ;

    if(identityObj.getAttributeMetaData(attrName)!=null){

      attrMetaData = identityObj.getAttributeMetaData(attrName) ;
      attrMetaData.setSource(source) ;

      attributeMetadataTobeSet.add(attrMetaData) ;

    }

    return attributeMetadataTobeSet ;
  }

  private Identity correctAttributeMetadata(Identity identityObj){


    List attributeMetadataTobeSet = new ArrayList() ;

    prepareAttributeMetaData(identityObj, "dob", "AD-AMITA:employeeType", attributeMetadataTobeSet) ;
    prepareAttributeMetaData(identityObj, "department", "AD-AMITA:employeeType", attributeMetadataTobeSet) ;
    prepareAttributeMetaData(identityObj, "ssn", "AD-AMITA:departmentNumber", attributeMetadataTobeSet) ;
    prepareAttributeMetaData(identityObj, "samAccountName", "AD-AMITA:samAccountName", attributeMetadataTobeSet) ;

    prepareAttributeMetaData(identityObj, "company", "$Ascension-Rule-Global-SetADAttribute", attributeMetadataTobeSet) ;
    prepareAttributeMetaData(identityObj, "locationDescription", "$Ascension-Rule-Global-SetADAttribute", attributeMetadataTobeSet) ;
    prepareAttributeMetaData(identityObj, "title", "$Ascension-Rule-Global-SetADAttribute", attributeMetadataTobeSet) ;
    prepareAttributeMetaData(identityObj, "buildingId", "$Ascension-Rule-Global-SetADAttribute", attributeMetadataTobeSet) ;
    prepareAttributeMetaData(identityObj, "departmentNumber", "$Ascension-Rule-Global-SetADAttribute", attributeMetadataTobeSet) ;

    prepareAttributeMetaData(identityObj, "manager", "$Ascension-Rule-Global-IdentityAttribute-Manager-from-Identity", attributeMetadataTobeSet) ;

    if (attributeMetadataTobeSet!=null && !attributeMetadataTobeSet.isEmpty()){

      identityObj.setAttributeMetaData(attributeMetadataTobeSet) ;
    }


    if(identityObj.getAttributeMetaData("city")!=null){

      identityObj.removeAttributeMetaData("city") ;

    }

    if(identityObj.getAttributeMetaData("isManager")!=null){

      identityObj.removeAttributeMetaData("isManager") ;

    }

    if(identityObj.getAttributeMetaData("jobcode")!=null){

      identityObj.removeAttributeMetaData("jobcode") ;

    }

    if(identityObj.getAttributeMetaData("jobcodeDesc")!=null){

      identityObj.removeAttributeMetaData("jobcodeDesc") ;

    }

    if(identityObj.getAttributeMetaData("businessUnitDescription")!=null){

      identityObj.removeAttributeMetaData("businessUnitDescription") ;

    }

    if(identityObj.getAttributeMetaData("market")!=null){

      identityObj.removeAttributeMetaData("market") ;

    }

    if(identityObj.getAttributeMetaData("employeeType")!=null){

      identityObj.removeAttributeMetaData("employeeType") ;

    }

    if(identityObj.getAttributeMetaData("employeeClass")!=null){

      identityObj.removeAttributeMetaData("employeeClass") ;

    }

    if(identityObj.getAttributeMetaData("hireDate")!=null){

      identityObj.removeAttributeMetaData("hireDate") ;

    }

    if(identityObj.getAttributeMetaData("jobFamily")!=null){

      identityObj.removeAttributeMetaData("jobFamily") ;

    }


    if(identityObj.getAttributeMetaData("operId")!=null){

      identityObj.removeAttributeMetaData("operId") ;

    }

    if(identityObj.getAttributeMetaData("managerLevel")!=null){

      identityObj.removeAttributeMetaData("managerLevel") ;

    }

    if(identityObj.getAttributeMetaData("type")!=null){

      identityObj.removeAttributeMetaData("type") ;

    }

    if(identityObj.getAttributeMetaData("identityType")!=null){

      identityObj.removeAttributeMetaData("identityType") ;

    }

    if(identityObj.getAttributeMetaData("lastHireDate")!=null){

      identityObj.removeAttributeMetaData("lastHireDate") ;

    }

    if(identityObj.getAttributeMetaData("businessUnit")!=null){

      identityObj.removeAttributeMetaData("businessUnit") ;

    }

    if(identityObj.getAttributeMetaData("location")!=null){

      identityObj.removeAttributeMetaData("location") ;

    }

    if(identityObj.getAttributeMetaData("badgeNumber")!=null){

      identityObj.removeAttributeMetaData("badgeNumber") ;

    }

    if(identityObj.getAttributeMetaData("employeeId")!=null){

      identityObj.removeAttributeMetaData("employeeId") ;

    }

    return identityObj ;

  }

  private void logAudit(Identity identityObj, String auditString1, String auditString2){

    try {

      AuditEvent event = new AuditEvent();

      event.setAction("comment");
      event.setTarget(identityObj.getName());
      event.setAttributeName("Process Name");
      event.setAttributeValue("Non-HR Contractor Cube Restoration");
      event.setString1(auditString1);
      event.setString2(auditString2);

      Auditor.log(event);
      context.commitTransaction();

    } catch (Exception exception){

      addMessage("logAudit() - Exception occured during log Auditr  - "+ exception.getMessage()) ;

    }
  }

  private String prepareAuditString1(String inputRecord){

    String[] inRecordValArray = inputRecord.split(DELIMITER) ;

    return 
      "{" +
      "name:"					+inRecordValArray[0]	+COMMA+
      "firstname:"				+inRecordValArray[1]	+COMMA+
      "lastname:"				+inRecordValArray[2]	+COMMA+
      "ssn:"					+inRecordValArray[3]	+COMMA+
      "dob:"					+inRecordValArray[4]	+COMMA+
      "manager:"				+inRecordValArray[5]	+COMMA+
      "isContractorManager:"	+inRecordValArray[6]	+COMMA+
      "contractorManager:"		+inRecordValArray[7]	+COMMA+
      "ctrexpdt:"				+inRecordValArray[8]	+COMMA+
      "title:"					+inRecordValArray[9]	+COMMA+
      "department:"				+inRecordValArray[10]	+COMMA+
      "departmentNumber:"		+inRecordValArray[11]	+
      "}" ;

  }

  private String prepareAuditString2(Identity identityObj, Identity managerObj){

    String manager = managerObj!=null ? managerObj.getName() : "" ;

    return 
      "{" +
      "name:"					+identityObj.getName()							+COMMA+
      "firstname:"				+identityObj.getAttribute("firstname")			+COMMA+
      "lastname:"				+identityObj.getAttribute("lastname")			+COMMA+
      "ssn:"					+identityObj.getAttribute("ssn")				+COMMA+
      "dob:"					+identityObj.getAttribute("dob")				+COMMA+
      "manager:"				+manager										+COMMA+
      "isContractorManager:"	+identityObj.getAttribute("isContractorManager")+COMMA+
      "contractorManager:"		+identityObj.getAttribute("contractorManager")	+COMMA+
      "ctrexpdt:"				+identityObj.getAttribute("ctrexpdt")			+COMMA+
      "title:"					+identityObj.getAttribute("title")				+COMMA+
      "department:"				+identityObj.getAttribute("department")			+COMMA+
      "departmentNumber:"		+identityObj.getAttribute("departmentNumber")	+
      "}" ;

  }

  processRestore() ;

  return outputMessages ;
